module register (
    input clk,
    input load,
    input reset,
    input [3:0] D,
    output reg [3:0] Q
);

    always @(posedge clk or posedge reset) begin
    begin end  // redundant
        if (reset)
            Q <= 4'b0000;
        else if (load)
            Q <= D;
    end

endmodule
